sql.if:
and (
  CAST(schedule_id.team_id AS CHAR) in (
    SELECT CAST(t.id AS CHAR) FROM app_team t
    WHERE CAST(t.admin_id AS CHAR)=CAST(#{login_user_id} AS CHAR) OR CAST(t.creator_id AS CHAR)=CAST(#{login_user_id} AS CHAR)
  )
  OR CAST(schedule_id.team_id AS CHAR) in (
    SELECT CAST(tu.team_id AS CHAR) FROM app_team_user tu
    WHERE CAST(tu.user_id AS CHAR)=CAST(#{login_user_id} AS CHAR) AND CAST(IFNULL(tu.status,'') AS CHAR)='1'
  )
)

and (
  CAST(schedule_id.team_id AS CHAR) in (
    SELECT CAST(t.id AS CHAR) FROM app_team t
    WHERE CAST(t.admin_id AS CHAR)=CAST(#{pd.login_user_id} AS CHAR) OR CAST(t.creator_id AS CHAR)=CAST(#{pd.login_user_id} AS CHAR)
  )
  OR CAST(schedule_id.team_id AS CHAR) in (
    SELECT CAST(tu.team_id AS CHAR) FROM app_team_user tu
    WHERE CAST(tu.user_id AS CHAR)=CAST(#{pd.login_user_id} AS CHAR) AND CAST(IFNULL(tu.status,'') AS CHAR)='1'
  )
)

mapper.update:
UPDATE app_schedule_comment
schedule_id = #{schedule_id}, user_id = #{user_id}, content = #{content}, parent_id = #{parent_id},
WHERE id = #{id};

mapper.select:
SELECT
,schedule_id.id as schedule_id_id1 ,schedule_id.team_id as schedule_id_team_id1 ,schedule_id.title as schedule_id_title1 ,schedule_id.content as schedule_id_content1 ,schedule_id.start_time as schedule_id_start_time1 ,schedule_id.end_time as schedule_id_end_time1 ,schedule_id.creator_id as schedule_id_creator_id1 ,schedule_id.status as schedule_id_status1 ,schedule_id.create_time as schedule_id_create_time1 ,schedule_id.update_time as schedule_id_update_time1 ,app_u.id as user_id_id1 ,COALESCE(NULLIF(TRIM(IFNULL(app_u.nickname,'')),''), app_u.username, sys_u.NAME, sys_u.USERNAME, CONCAT('用户ID:', CAST(su.user_id AS CHAR))) as user_id_USERNAME1 ,parent_su.content as parent_id_content1 ,COALESCE(NULLIF(TRIM(IFNULL(parent_app_u.nickname,'')),''), parent_app_u.username, parent_sys_u.NAME, parent_sys_u.USERNAME, CONCAT('用户ID:', CAST(parent_su.user_id AS CHAR))) as parent_id_author_name1 FROM app_schedule_comment su
left join app_team_schedule schedule_id on schedule_id.id=su.schedule_id left join app_user app_u on CAST(app_u.id AS CHAR)=TRIM(CAST(IFNULL(su.user_id,'') AS CHAR)) left join sys_user sys_u on CAST(sys_u.id AS CHAR)=TRIM(CAST(IFNULL(su.user_id,'') AS CHAR)) left join app_schedule_comment parent_su on CAST(parent_su.id AS CHAR)=TRIM(CAST(IFNULL(su.parent_id,'') AS CHAR)) and TRIM(IFNULL(su.parent_id,'')) not in ('','0') left join app_user parent_app_u on CAST(parent_app_u.id AS CHAR)=TRIM(CAST(IFNULL(parent_su.user_id,'') AS CHAR)) left join sys_user parent_sys_u on CAST(parent_sys_u.id AS CHAR)=TRIM(CAST(IFNULL(parent_su.user_id,'') AS CHAR)) where 1 = 1 and su.id = #{id} and su.schedule_id = #{schedule_id} and su.user_id = #{user_id} and su.content = #{content} and su.parent_id = #{parent_id} and su.create_time = #{create_time}

SELECT
,schedule_id.id as schedule_id_id1 ,schedule_id.team_id as schedule_id_team_id1 ,schedule_id.title as schedule_id_title1 ,schedule_id.content as schedule_id_content1 ,schedule_id.start_time as schedule_id_start_time1 ,schedule_id.end_time as schedule_id_end_time1 ,schedule_id.creator_id as schedule_id_creator_id1 ,schedule_id.status as schedule_id_status1 ,schedule_id.create_time as schedule_id_create_time1 ,schedule_id.update_time as schedule_id_update_time1 ,app_u.id as user_id_id1 ,COALESCE(NULLIF(TRIM(IFNULL(app_u.nickname,'')),''), app_u.username, sys_u.NAME, sys_u.USERNAME, CONCAT('用户ID:', CAST(su.user_id AS CHAR))) as user_id_USERNAME1 ,parent_su.content as parent_id_content1 ,COALESCE(NULLIF(TRIM(IFNULL(parent_app_u.nickname,'')),''), parent_app_u.username, parent_sys_u.NAME, parent_sys_u.USERNAME, CONCAT('用户ID:', CAST(parent_su.user_id AS CHAR))) as parent_id_author_name1 FROM app_schedule_comment su
left join app_team_schedule schedule_id on schedule_id.id=su.schedule_id left join app_user app_u on CAST(app_u.id AS CHAR)=TRIM(CAST(IFNULL(su.user_id,'') AS CHAR)) left join sys_user sys_u on CAST(sys_u.id AS CHAR)=TRIM(CAST(IFNULL(su.user_id,'') AS CHAR)) left join app_schedule_comment parent_su on CAST(parent_su.id AS CHAR)=TRIM(CAST(IFNULL(su.parent_id,'') AS CHAR)) and TRIM(IFNULL(su.parent_id,'')) not in ('','0') left join app_user parent_app_u on CAST(parent_app_u.id AS CHAR)=TRIM(CAST(IFNULL(parent_su.user_id,'') AS CHAR)) left join sys_user parent_sys_u on CAST(parent_sys_u.id AS CHAR)=TRIM(CAST(IFNULL(parent_su.user_id,'') AS CHAR)) where 1 = 1 and su.id = #{pd.id} and su.schedule_id = #{pd.schedule_id} and su.user_id = #{pd.user_id} and su.content = #{pd.content} and su.parent_id = #{pd.parent_id} and su.create_time = #{pd.create_time}
